/-- Elementwise map over a matrix. -/
def matrixMap (f : Real → Real) (H : MatState K V) : MatState K V :=
  Matrix.of fun i j => f (H i j)

/-- Outer product `k v^T`, with shape `K x V`. -/
def outerKV (k : Vec K) (v : Vec V) : MatState K V :=
  Matrix.of fun i j => k i * v j

/-- Query readout `H^T q`, with shape `V`. -/
def queryReadout (H : MatState K V) (q : Vec K) : Vec V :=
  H.transpose.mulVec q

/-- Apply a one-step update twice with given inputs. -/
def twoStep (update : OneStepUpdate) (H : TwoMat) (k1 v1 k2 v2 : TwoVec) : TwoMat :=
  update (update H k1 v1) k2 v2

/-- Inner product on key vectors. -/
def keyDot (k q : KeyVec K) : Real :=
  Finset.univ.sum fun i => k i * q i

/-- Read a value vector from memory by query key. -/
def read (S : Memory K V) (q : KeyVec K) : ValueVec V :=
  M2RNNComparison.queryReadout S q

/-- Retrieval error at key `k`: the correction needed to make `read S k = v`. -/
def correction (S : Memory K V) (k : KeyVec K) (v : ValueVec V) : ValueVec V :=
  v - read S k

