/-- Run the tracker from an arbitrary starting state. -/
def runFrom (p : State) (w : List AdjacentGenerator) : State :=
  w.foldl step p

/-- Run the tracker from the identity state. -/
def run (w : List AdjacentGenerator) : State :=
  runFrom 1 w

